@app.route('/dashboard', methods=['POST'])
def dashboard_page():
    # Prepare featured_books - let's choose top 5 by stock descending for featured
    books = read_books()
    featured_books = sorted(books, key=lambda b: b['stock'], reverse=True)[:5]

    # Prepare bestsellers for 'This Month' as default
    all_bestsellers = read_bestsellers()
    bestsellers_filtered = [b for b in all_bestsellers if b['period'] == 'This Month']
    # Attach book info
    books_map = {b['book_id']: b for b in books}
    best_sellers = []
    for bs in bestsellers_filtered:
        book = books_map.get(bs['book_id'])
        if book:
            best_sellers.append({
                'book_id': book['book_id'],
                'title': book['title'],
                'author': book['author'],
                'sales': bs['sales_count']
            })

    return render_template('dashboard.html', featured_books=featured_books, best_sellers=best_sellers)

@app.route('/catalog', methods=['GET', 'PUT'])
def catalog_page():
    books = read_books()
    categories = read_categories()
    # filters from query params (search, category_filter)
    search = request.args.get('search', '') if request.method == 'GET' else request.form.get('search', '')
    category_filter = request.args.get('category_filter', 'All') if request.method == 'GET' else request.form.get('category_filter', 'All')

    filtered_books = filter_books_by_search_category(books, search, category_filter)

    filters = {
        'search': search,
        'category_filter': category_filter
    }

    return render_template('catalog.html', books=filtered_books, categories=categories, filters=filters)

@app.route('/book/<string:book_id>', methods=['GET', 'DELETE', 'POST'])
def book_details_page(book_id):
    try:
        book_id_int = int(book_id)
    except:
        abort(404)

    book = find_book_by_id(book_id_int)
    if not book:
        abort(404)

    reviews_all = read_reviews()
    # filter reviews for this book
    reviews = [r for r in reviews_all if r['book_id'] == book_id_int]

    if request.method == 'POST':
        # Handle add to cart
        cart_items = read_cart()
        # check if book already in cart
        existing = None
        for item in cart_items:
            if item['book_id'] == book_id_int:
                existing = item
                break
        if existing:
            existing['quantity'] += 1
        else:
            new_cart_id = get_next_id(cart_items, 'cart_id')
            today_str = datetime.today().strftime('%Y-%m-%d')
            cart_items.append({
                'cart_id': new_cart_id,
                'book_id': book_id_int,
                'quantity': 1,
                'added_date': today_str
            })
        save_cart(cart_items)
        return redirect(url_for('book_details_page', book_id=book_id))

    elif request.method == 'DELETE':
        # Remove book from cart regardless of quantity
        cart_items = read_cart()
        cart_items = [item for item in cart_items if item['book_id'] != book_id_int]
        save_cart(cart_items)
        return ('', 204)

    else:  # GET
        return render_template('book_details.html', book=book, reviews=reviews)

@app.route('/cart', methods=['GET', 'PUT', 'POST'])
def cart_page():
    cart_items = read_cart()
    books = {b['book_id']: b for b in read_books()}

    if request.method == 'POST' or request.method == 'PUT':
        # Update quantities or remove items
        cart_data = request.form
        # form keys expected: update-quantity-{cart_id} or remove-item-{cart_id}
        to_remove = set()
        to_update = {}
        for key in cart_data.keys():
            if key.startswith('update-quantity-'):
                try:
                    cart_id = int(key[len('update-quantity-'):])
                    quantity = int(cart_data[key])
                    if quantity < 1:
                        to_remove.add(cart_id)
                    else:
                        to_update[cart_id] = quantity
                except:
                    continue
            elif key.startswith('remove-item-button-'):
                try:
                    cart_id = int(key[len('remove-item-button-'):])
                    to_remove.add(cart_id)
                except:
                    continue
        # Remove items
        cart_items = [item for item in cart_items if item['cart_id'] not in to_remove]
        # Update quantities
        for item in cart_items:
            if item['cart_id'] in to_update:
                item['quantity'] = to_update[item['cart_id']]
        save_cart(cart_items)
        return redirect(url_for('cart_page'))

    # GET
    # Prepare cart items with book info
    cart_display = []
    total_amount = 0.0
    for item in cart_items:
        book = books.get(item['book_id'])
        if book:
            subtotal = book['price'] * item['quantity']
            total_amount += subtotal
            cart_display.append({
                'cart_id': item['cart_id'],
                'book': book,
                'quantity': item['quantity'],
                'price': book['price'],
                'subtotal': subtotal
            })

    return render_template('cart.html', cart_items=cart_display, total_amount=total_amount)

@app.route('/checkout', methods=['GET', 'POST'])
def checkout_page():
    cart_items = read_cart()
    books = {b['book_id']: b for b in read_books()}

    cart_display = []
    total_amount = 0.0

    for item in cart_items:
        book = books.get(item['book_id'])
        if book:
            subtotal = book['price'] * item['quantity']
            total_amount += subtotal
            cart_display.append({
                'cart_id': item['cart_id'],
                'book': book,
                'quantity': item['quantity'],
                'price': book['price'],
                'subtotal': subtotal
            })

    if request.method == 'POST':
        customer_name = request.form.get('customer_name', '').strip()
        shipping_address = request.form.get('shipping_address', '').strip()
        payment_method = request.form.get('payment_method', '').strip()

        if not customer_name or not shipping_address or not payment_method:
            # Could add flash message for missing fields
            return render_template('checkout.html', cart_items=cart_display)

        orders = read_orders()
        order_items = read_order_items()

        new_order_id = get_next_id(orders, 'order_id')
        today_str = datetime.today().strftime('%Y-%m-%d')

        new_order = {
            'order_id': new_order_id,
            'customer_name': customer_name,
            'order_date': today_str,
            'total_amount': total_amount,
            'status': 'Pending',
            'shipping_address': shipping_address
        }
        orders.append(new_order)
        save_orders(orders)

        # Add order items
        current_order_item_id = get_next_id(order_items, 'order_item_id')
        for item in cart_items:
            book_id = item['book_id']
            quantity = item['quantity']
            price = books[book_id]['price']
            order_item = {
                'order_item_id': current_order_item_id,
                'order_id': new_order_id,
                'book_id': book_id,
                'quantity': quantity,
                'price': price
            }
            order_items.append(order_item)
            current_order_item_id += 1
        save_order_items(order_items)

        # Clear cart
        save_cart([])

        return redirect(url_for('order_history_page'))

    return render_template('checkout.html', cart_items=cart_display)

