@app.route('/write-review', methods=['GET', 'POST'])
def write_review_page():
    books = read_books()
    # For books purchased, no indication on how to filter, so we show all books
    books_purchased = books

    if request.method == 'POST':
        book_id_str = request.form.get('book_id')
        rating_str = request.form.get('rating')
        review_text = request.form.get('review_text', '').strip()
        customer_name = 'Anonymous'  # As per spec, no form field for customer name, so set anonymous

        # Validate inputs
        try:
            book_id = int(book_id_str)
            rating = int(rating_str)
            if rating < 1 or rating > 5:
                raise ValueError
            if not review_text:
                raise ValueError
        except:
            # Re-render page on error
            return render_template('write_review.html', books_purchased=books_purchased)

        reviews = read_reviews()
        new_review_id = get_next_id(reviews, 'review_id')
        today_str = datetime.today().strftime('%Y-%m-%d')
        new_review = {
            'review_id': new_review_id,
            'book_id': book_id,
            'customer_name': customer_name,
            'rating': rating,
            'review_text': review_text,
            'review_date': today_str
        }
        reviews.append(new_review)
        save_reviews(reviews)

        # After submission redirect to reviews page
        return redirect(url_for('reviews_page'))

    return render_template('write_review.html', books_purchased=books_purchased)

@app.route('/bestsellers', methods=['GET', 'POST'])
def bestsellers_page():
