@app.route('/cart', methods=['GET', 'PUT', 'POST'])
def cart_page():
    cart_items = read_cart()
    books = {b['book_id']: b for b in read_books()}

    if request.method == 'POST' or request.method == 'PUT':
        # Update quantities or remove items
        cart_data = request.form
        # form keys expected: update-quantity-{cart_id} or remove-item-{cart_id}
        to_remove = set()
        to_update = {}
        for key in cart_data.keys():
            if key.startswith('update-quantity-'):
                try:
                    cart_id = int(key[len('update-quantity-'):])
                    quantity = int(cart_data[key])
                    if quantity < 1:
                        to_remove.add(cart_id)
                    else:
                        to_update[cart_id] = quantity
                except:
                    continue
            elif key.startswith('remove-item-button-'):
                try:
                    cart_id = int(key[len('remove-item-button-'):])
                    to_remove.add(cart_id)
                except:
                    continue
        # Remove items
        cart_items = [item for item in cart_items if item['cart_id'] not in to_remove]
        # Update quantities
        for item in cart_items:
            if item['cart_id'] in to_update:
                item['quantity'] = to_update[item['cart_id']]
        save_cart(cart_items)
        return redirect(url_for('cart_page'))

    # GET
    # Prepare cart items with book info
    cart_display = []
    total_amount = 0.0
    for item in cart_items:
        book = books.get(item['book_id'])
        if book:
            subtotal = book['price'] * item['quantity']
            total_amount += subtotal
            cart_display.append({
                'cart_id': item['cart_id'],
                'book': book,
                'quantity': item['quantity'],
                'price': book['price'],
                'subtotal': subtotal
            })

    return render_template('cart.html', cart_items=cart_display, total_amount=total_amount)

@app.route('/checkout', methods=['GET', 'POST'])
def checkout_page():
    cart_items = read_cart()
    books = {b['book_id']: b for b in read_books()}

    cart_display = []
    total_amount = 0.0

    for item in cart_items:
        book = books.get(item['book_id'])
        if book:
            subtotal = book['price'] * item['quantity']
            total_amount += subtotal
            cart_display.append({
                'cart_id': item['cart_id'],
                'book': book,
                'quantity': item['quantity'],
                'price': book['price'],
                'subtotal': subtotal
            })

    if request.method == 'POST':
        customer_name = request.form.get('customer_name', '').strip()
        shipping_address = request.form.get('shipping_address', '').strip()
        payment_method = request.form.get('payment_method', '').strip()

        if not customer_name or not shipping_address or not payment_method:
            # Could add flash message for missing fields
            return render_template('checkout.html', cart_items=cart_display)

        orders = read_orders()
        order_items = read_order_items()

        new_order_id = get_next_id(orders, 'order_id')
        today_str = datetime.today().strftime('%Y-%m-%d')

        new_order = {
            'order_id': new_order_id,
            'customer_name': customer_name,
            'order_date': today_str,
            'total_amount': total_amount,
            'status': 'Pending',
            'shipping_address': shipping_address
        }
        orders.append(new_order)
        save_orders(orders)

        # Add order items
        current_order_item_id = get_next_id(order_items, 'order_item_id')
        for item in cart_items:
            book_id = item['book_id']
            quantity = item['quantity']
            price = books[book_id]['price']
            order_item = {
                'order_item_id': current_order_item_id,
                'order_id': new_order_id,
                'book_id': book_id,
                'quantity': quantity,
                'price': price
            }
            order_items.append(order_item)
            current_order_item_id += 1
        save_order_items(order_items)

        # Clear cart
        save_cart([])

        return redirect(url_for('order_history_page'))

    return render_template('checkout.html', cart_items=cart_display)

