        except:
            pass
    return render_template('reviews.html', reviews=reviews, rating_filter=rating_filter)

@app.route('/write-review', methods=['GET', 'POST'])
def write_review_page():
    books_purchased = read_books()  # spec offers no filtering
    timeperiod = 'All Times'

    if request.method == 'POST':
        book_id_raw = request.form.get('book_id')
        rating_raw = request.form.get('rating')
        review_text = request.form.get('review_text', '').strip()

        try:
            book_id = int(book_id_raw)
            rating = int(rating_raw)
            if rating < 1 or rating > 5 or not review_text:
                raise ValueError
        except:
            return render_template('write_review.html', books_purchased=books_purchased, timeperiod=timeperiod)

        reviews = read_reviews()
        new_review_id = get_next_id(reviews, 'review_id')
        today = datetime.today().strftime('%Y-%m-%d')
        new_review = {
            'review_id': new_review_id,
            'book_id': book_id,
            'customer_name': 'Anonymous',
            'rating': rating,
            'review_text': review_text,
            'review_date': today
        }
        reviews.append(new_review)
        save_reviews(reviews)

        return redirect(url_for('reviews_page'))

    return render_template('write_review.html', books_purchased=books_purchased, timeperiod=timeperiod)

@app.route('/bestsellers', methods=['GET', 'POST'])
def bestsellers_page():
    time_period = request.args.get('time_period', None)
    if not time_period and request.method == 'POST':
        time_period = request.form.get('time_period', 'This Month')
    if not time_period:
