    statusfilter = 'All'  # as a placeholder
    orderitems = []
    ratingfilter = 'All'  # all ratings filter

    if request.method == 'DELETE':
        # Spec unclear on exact purpose, so just return empty response
        return ('', 204)

    if request.method == 'POST':
        customer_name = request.form.get('customer_name', '').strip()
        shipping_address = request.form.get('shipping_address', '').strip()
        payment_method = request.form.get('payment_method', '').strip()

        if not customer_name or not shipping_address or not payment_method:
            # Invalid submission, just re-render
            return render_template('checkout.html', cart_items=cart_display, statusfilter=statusfilter, orderitems=orderitems, ratingfilter=ratingfilter)

        orders = read_orders()
        orderitems_all = read_order_items()

        new_order_id = get_next_id(orders, 'order_id')
        today = datetime.today().strftime('%Y-%m-%d')
        total_amount = calculate_cart_total(cart_display)

        new_order = {
            'order_id': new_order_id,
            'customer_name': customer_name,
            'order_date': today,
            'total_amount': total_amount,
            'status': 'Pending',
            'shipping_address': shipping_address
        }

        orders.append(new_order)
        save_orders(orders)

        current_order_item_id = get_next_id(orderitems_all, 'order_item_id')
        for item in cart_items:
            order_item = {
                'order_item_id': current_order_item_id,
                'order_id': new_order_id,
                'book_id': item['book_id'],
                'quantity': item['quantity'],
                'price': item['quantity'] * next((b['price'] for b in read_books() if b['book_id']==item['book_id']), 0)
            }
            orderitems_all.append(order_item)
            current_order_item_id += 1

        save_order_items(orderitems_all)

        # Do not clear cart.txt according to spec

        return redirect(url_for('order_history_page'))

    # GET method
    return render_template('checkout.html', cart_items=cart_display, statusfilter=statusfilter, orderitems=orderitems, ratingfilter=ratingfilter)

@app.route('/orders', methods=['GET'])
def order_history_page():
    status_filter = request.args.get('status_filter', 'All')
    orders = read_orders()
    if status_filter != 'All':
        orders = [o for o in orders if o['status'] == status_filter]
    return render_template('orders.html', orders=orders, status_filter=status_filter)

@app.route('/orders/<int:order_id>', methods=['GET'])
def order_details_page(order_id):
    orders = read_orders()
    order = next((o for o in orders if o['order_id'] == order_id), None)
    if not order:
        abort(404)

    order_items_all = read_order_items()
    books = {b['book_id']: b for b in read_books()}
    order_items = []
    for item in order_items_all:
        if item['order_id'] == order_id:
            book = books.get(item['book_id'])
            if book:
                order_items.append({
                    'order_item_id': item['order_item_id'],
                    'book': book,
                    'quantity': item['quantity'],
                    'price': item['price']
                })

    return render_template('order_details.html', order=order, order_items=order_items)

@app.route('/reviews', methods=['GET'])
def reviews_page():
    rating_filter = request.args.get('rating_filter', 'All')
    reviews = read_reviews()
    if rating_filter != 'All':
        try:
            rating_filter_int = int(rating_filter)
            reviews = [r for r in reviews if r['rating'] == rating_filter_int]
        except:
            pass
    return render_template('reviews.html', reviews=reviews, rating_filter=rating_filter)

@app.route('/write-review', methods=['GET', 'POST'])
def write_review_page():
    books_purchased = read_books()  # spec offers no filtering
    timeperiod = 'All Times'

    if request.method == 'POST':
        book_id_raw = request.form.get('book_id')
        rating_raw = request.form.get('rating')
        review_text = request.form.get('review_text', '').strip()

        try:
            book_id = int(book_id_raw)
            rating = int(rating_raw)
            if rating < 1 or rating > 5 or not review_text:
                raise ValueError
        except:
            return render_template('write_review.html', books_purchased=books_purchased, timeperiod=timeperiod)

        reviews = read_reviews()
        new_review_id = get_next_id(reviews, 'review_id')
        today = datetime.today().strftime('%Y-%m-%d')
        new_review = {
            'review_id': new_review_id,
            'book_id': book_id,
            'customer_name': 'Anonymous',
            'rating': rating,
            'review_text': review_text,
            'review_date': today
        }
        reviews.append(new_review)
        save_reviews(reviews)

        return redirect(url_for('reviews_page'))

    return render_template('write_review.html', books_purchased=books_purchased, timeperiod=timeperiod)

@app.route('/bestsellers', methods=['GET', 'POST'])
def bestsellers_page():
    time_period = request.args.get('time_period', None)
    if not time_period and request.method == 'POST':
        time_period = request.form.get('time_period', 'This Month')
    if not time_period:
        time_period = 'This Month'

    bestsellers = read_bestsellers()
    filtered = [b for b in bestsellers if b['period'] == time_period]
    books = {b['book_id']: b for b in read_books()}
    result = []
    for b in filtered:
        book = books.get(b['book_id'])
        if book:
            result.append({
                'book_id': book['book_id'],
                'title': book['title'],
                'author': book['author'],
                'sales': b['sales_count']
            })
    return render_template('bestsellers.html', bestsellers=result, time_period=time_period)


